	return fmt.Sprintf(
		"Plan %s. Goal: %s. "+
			"Use the `kasmos-planner` skill. "+
			"The plan MUST include ## Wave N sections (at minimum ## Wave 1) "+
			"grouping all tasks — kasmos requires Wave headers to orchestrate implementation.",
		planName, description,
	)
}

